const packageJson = await readFile({ path: "package.json" })
if (packageJson !== null) {
  const parsed = JSON.parse(packageJson)
  console.log(`Package: ${parsed.name}@${parsed.version}`)
}
const entries = await ls(".")
console.log(entries.join("\n"))
await taskComplete(`Listed ${entries.length} top-level entries for "list the workspace".`)

